import Sidebar from '../components/Sidebar';
import startImage from '../assets/mainpage.png';

function NewsPage() {
  return (
    <div className="relative w-full min-h-screen bg-white overflow-hidden">
      {/* 배경 이미지 */}
      <img
        src={startImage}
        alt="배경"
        className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-full h-full object-cover opacity-20 blur-2xl -z-10"
      />

      {/* 전체 레이아웃 */}
      <div className="relative z-10 flex px-8 pt-12 items-start">
        {/* 사이드바 */}
        <Sidebar />

        {/* 본문 */}
        <main className="flex-1 px-8">
          {/* 제목 */}
          <h2 className="text-2xl font-bold text-gray-800 mb-8">소식</h2>

          {/* 청약 정보 카드 */}
          <section className="grid grid-cols-3 gap-6 mb-16">
            {[
              'LH 청약 정보',
              'SH 청약 정보',
              'GH 청약 정보',
            ].map((title, i) => (
              <div
                key={i}
                className="h-[180px] rounded-xl bg-white/80 backdrop-blur-sm border border-blue-300 flex items-center justify-center text-blue-600 font-bold text-lg shadow"
              >
                {title}
              </div>
            ))}
          </section>

          {/* 최신 뉴스 카드 */}
          <section className="grid grid-cols-3 gap-6">
            {[1, 2, 3, 4, 5, 6].map((i) => (
              <div
                key={i}
                className="w-full h-[320px] bg-white/80 backdrop-blur-sm border border-gray-200 rounded-xl shadow flex flex-col overflow-hidden"
              >
                {/* 썸네일 영역 */}
                <div className="h-[220px] bg-blue-500 flex items-center justify-center text-white text-lg font-semibold">
                  뉴스 이미지
                </div>
                {/* 제목 */}
                <div className="flex-1 p-4 flex items-center justify-center text-center">
                  <p className="text-sm text-gray-800 font-medium">
                    뉴스 제목 {i}
                  </p>
                </div>
              </div>
            ))}
          </section>
        </main>
      </div>
    </div>
  );
}

export default NewsPage;
